pub fn problemdetails_method_not_allowed(detail: String) -> ProblemDetails {
    spikard::ProblemDetails::method_not_allowed(detail).into()
}

/// Create an internal server error
#[rustler::nif]
pub fn problemdetails_internal_server_error(detail: String) -> ProblemDetails {
    spikard::ProblemDetails::internal_server_error(detail).into()
}

/// Create a bad request error
#[rustler::nif]
pub fn problemdetails_bad_request(detail: String) -> ProblemDetails {
    spikard::ProblemDetails::bad_request(detail).into()
}

/// Serialize to JSON string
///
/// # Errors
/// Returns an error if the serialization fails.
#[rustler::nif]
pub fn problemdetails_to_json(obj: ProblemDetails) -> Result<String, String> {
    let result = spikard::ProblemDetails::from(obj)
        .to_json()
        .map_err(|e| e.to_string())?;
    Ok(result)
}

/// Serialize to pretty JSON string
///
/// # Errors
/// Returns an error if the serialization fails.
#[rustler::nif]
pub fn problemdetails_to_json_pretty(obj: ProblemDetails) -> Result<String, String> {
    let result = spikard::ProblemDetails::from(obj)
        .to_json_pretty()
        .map_err(|e| e.to_string())?;
    Ok(result)
}

/// Convert error to HTTP status code
///
/// Maps GraphQL error types to appropriate HTTP status codes:
/// - 400: Bad Request for parse/request-handling errors
/// - 401: Unauthorized for authentication errors
/// - 403: Forbidden for authorization errors
/// - 404: Not Found for resource not found
/// - 422: Unprocessable Entity for validation failures
/// - 429: Too Many Requests for rate limit errors
/// - 500: Internal Server Error for schema/serialization/internal errors
/// - 200: OK for GraphQL execution errors returned in GraphQL response body
///
/// # Examples
///
/// ```ignore
/// use spikard_graphql::error::GraphQLError;
///
/// let error = GraphQLError::AuthenticationError("Invalid token".to_string());
/// assert_eq!(error.status_code(), 401);
///
/// let error = GraphQLError::ExecutionError("Query failed".to_string());
/// assert_eq!(error.status_code(), 200); // GraphQL spec: errors return 200 with errors in body
/// ```
#[rustler::nif]
pub fn graphqlerror_status_code(resource: rustler::ResourceArc<GraphQLError>) -> u16 {
    resource.inner.status_code()
}

/// Set the HTTP path for the GraphQL endpoint
///
/// # Arguments
///
/// * `path` - The URL path (e.g., "/graphql", "/api/graphql")
#[rustler::nif]
pub fn graphqlrouteconfig_path(
    resource: rustler::ResourceArc<GraphQLRouteConfig>,
    path: String,
) -> ResourceArc<GraphQLRouteConfig> {
    ResourceArc::new(GraphQLRouteConfig {
        inner: Arc::new((*resource.inner).clone().path(path)),
    })
}

/// Set the HTTP method for the GraphQL endpoint
///
/// # Arguments
///
/// * `method` - The HTTP method (typically "POST")
#[rustler::nif]
pub fn graphqlrouteconfig_method(
    resource: rustler::ResourceArc<GraphQLRouteConfig>,
    method: String,
) -> ResourceArc<GraphQLRouteConfig> {
    ResourceArc::new(GraphQLRouteConfig {
        inner: Arc::new((*resource.inner).clone().method(method)),
    })
}

