/// Convert a `spikard_graphql::error::GraphQLError` error to a Rustler error string.
#[allow(dead_code)]
fn graph_q_l_error_to_rustler_err(e: spikard_graphql::error::GraphQLError) -> String {
    e.to_string()
}

/// Convert a `spikard_graphql::schema::SchemaError` error to a Rustler error string.
#[allow(dead_code)]
fn schema_error_to_rustler_err(e: spikard_graphql::schema::SchemaError) -> String {
    e.to_string()
}

fn on_load(env: rustler::Env, _info: rustler::Term) -> bool {
    env.register::<GraphQLError>()
        .expect("Failed to register resource type GraphQLError");
    env.register::<GraphQLRouteConfig>()
        .expect("Failed to register resource type GraphQLRouteConfig");
    true
}

rustler::init!("Elixir.Spikard.Native", load = on_load);
